DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserLinearRelation.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
@h = (-9..9)[NchooseK(19,2)];
@k = (-9..9)[NchooseK(19,2)];
@b;
@possible_m;
for my $m1 (-9..-2,2..9) {
  for my $m2 (-9..-2,2..9) {
    @b = ($k[0] - $m1*$h[0], $k[1] - $m2*$h[1]);
    push(@possible_m,[$m1,$m2]) if (
      abs($m2 - $m1) > 1 &&
      abs($m2 - $m1) < 10 &&
      ($b[0] - $b[1]) % ($m2 - $m1) != 0 &&
      ($m2*$b[0] - $m1*$b[1]) % ($m2 - $m1) != 0
    );
  }
}
@m = @{list_random(@possible_m)};
@b = map {$k[$_] - $m[$_]*$h[$_]} (0,1);
Context("Fraction")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
parser::Assignment->Allow;
$x = Fraction(($b[0] - $b[1])/($m[1] - $m[0]));
$y = Fraction(($m[1]*$b[0] - $m[0]*$b[1])/($m[1] - $m[0]));
@right = map{Formula("$m[$_] ($X - $h[$_]) + $k[$_]")->reduce} (0,1);
@f = map{Formula("$Y = $right[$_]")->reduce} (0,1);
$xis = Formula("$X = $x");
$yis = Formula("$Y = $y");
$solution = List($xis,$yis);
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$answer = $solution->cmp(
  mathQuillOpts => 'disabled'
);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$f[0]] \\
                  \amp [$f[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
